import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Profile.css';

function Profile() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [userData, setUserData] = useState({
    email: '',
    name: '',
    age: '',
    sex: '',
    smoking: '',
    allergy: ''
  });
  const [originalData, setOriginalData] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [userRole, setUserRole] = useState('user');

  useEffect(() => {
    const fetchUserData = async () => {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      try {
        // Fetch user data
        const response = await fetch(`http://localhost:5000/api/user-data/${user_id}`);
        const data = await response.json();

        if (response.ok) {
          // Fetch email from users table
          const emailResponse = await fetch(`http://localhost:5000/api/user-email/${user_id}`);
          const emailData = await emailResponse.json();

          if (emailResponse.ok) {
            const completeData = {
              ...data,
              email: emailData.email,
              smoking: data.smoking === 1 ? 'yes' : 'no', // Convert smoking value to yes/no
              sex: data.sex // Keep the sex value as is from the database
            };
            setUserData(completeData);
            setOriginalData(completeData);
          } else {
            throw new Error(emailData.error);
          }
        } else {
          throw new Error(data.error);
        }
      } catch (error) {
        console.error('Error fetching user data:', error);
        setError('Failed to load user data');
      } finally {
        setIsLoading(false);
      }
    };

    fetchUserData();
    checkUserRole();
  }, [navigate]);

  // Check user role
  const checkUserRole = async () => {
    try {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      const response = await fetch(`http://localhost:5000/api/user-role/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to verify user role');
      }

      const data = await response.json();
      setUserRole(data.role || 'user');
    } catch (error) {
      console.error('Error checking user role:', error);
      setUserRole('user');
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setUserData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      // Update user data
      const response = await fetch(`http://localhost:5000/api/update-user-data/${user_id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          name: userData.name,
          age: userData.age,
          sex: userData.sex, // Send sex value as is to the database
          smoking: userData.smoking === 'yes' ? 1 : 0, // Convert smoking value back to 1/0
          allergy: userData.allergy
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to update user data');
      }

      // Update email if changed
      if (userData.email !== originalData.email) {
        const emailResponse = await fetch(`http://localhost:5000/api/update-email/${user_id}`, {
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ email: userData.email }),
        });

        if (!emailResponse.ok) {
          throw new Error('Failed to update email');
        }
      }

      setSuccess('Changes saved successfully');
      setOriginalData(userData);
    } catch (error) {
      console.error('Error updating user data:', error);
      setError('Failed to save changes');
    }
  };

  const hasChanges = () => {
    if (!originalData) return false;
    return Object.keys(userData).some(key => userData[key] !== originalData[key]);
  };

  if (isLoading) {
    return <div className="profile-container">Loading...</div>;
  }

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  const handleHome = () => {
    // Redirect to admin dashboard if user is admin, otherwise to regular dashboard
    if (userRole === 'admin') {
      navigate('/admin-dashboard');
    } else {
      navigate('/dashboard');
    }
  };

  return (
    <div className={`profile-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Profile Settings</h1>
        </div>

        <div className="nav-buttons">
          <button 
            className="logout-button"
            onClick={() => {
              localStorage.removeItem('user_id');
              navigate('/');
            }}
          >
            Logout
          </button>
        </div>
      </div>
      <div className="profile-content">
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}
        <form onSubmit={handleSubmit} className="profile-form">
          <div className="profile-form-group">
            <label htmlFor="email">Email</label>
            <input
              type="email"
              id="email"
              name="email"
              value={userData.email}
              onChange={handleChange}
              required
            />
          </div>
          <div className="profile-form-group">
            <label htmlFor="name">Name</label>
            <input
              type="text"
              id="name"
              name="name"
              value={userData.name}
              onChange={handleChange}
              required
            />
          </div>
          <div className="profile-form-group">
            <label htmlFor="age">Age</label>
            <input
              type="number"
              id="age"
              name="age"
              value={userData.age}
              onChange={handleChange}
              required
              min="1"
            />
          </div>
          <div className="profile-form-group">
            <label htmlFor="sex">Gender</label>
            <select
              id="sex"
              name="sex"
              value={userData.sex}
              onChange={handleChange}
              required
            >
              <option value="">Select Gender</option>
              <option value="male">Male</option>
              <option value="female">Female</option>
            </select>
          </div>
          <div className="profile-form-group">
            <label className="radio-label">Smoking Status</label>
            <div className="radio-group">
              <label>
                <input
                  type="radio"
                  name="smoking"
                  value="yes"
                  checked={userData.smoking === 'yes'}
                  onChange={handleChange}
                  required
                />
                Yes
              </label>
              <label>
                <input
                  type="radio"
                  name="smoking"
                  value="no"
                  checked={userData.smoking === 'no'}
                  onChange={handleChange}
                />
                No
              </label>
            </div>
          </div>
          <div className="profile-form-group">
            <label htmlFor="allergy">Allergies</label>
            <input
              type="text"
              id="allergy"
              name="allergy"
              value={userData.allergy}
              onChange={handleChange}
              required
            />
          </div>
          <button 
            type="submit" 
            className="save-button"
            disabled={!hasChanges()}
          >
            Save Changes
          </button>
        </form>
